<template>
    <section>
        <h2 id="global-icon-size"><a class="anchorjs-link font_2" href="#global-icon-size" aria-label="Anchor link for: global-icon-size"></a>icon</h2>
        <p class="text_des font_4">提供  .icon_1 到 .icon_5  5个类  赋予相应的 icon 不同大小样式 </p>

        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <table class="font-table">
                <thead>
                <tr>
                    <th width="100">样式</th>
                    <th width="150">举例</th>
                </tr>
                </thead>
                <tbody>
                <tr v-for="item in iconStyle">
                    <td>{{ item.style }}</td>
                    <td>
                        <i class="iconfont icon-bianji" :class="item.style"></i>
                    </td>
                </tr>
                </tbody>
            </table>
        </div>

        <figure class="highlight"><pre v-highlightA><code>
    &lt;i class="iconfont icon-bianji icon_1"&gt;&lt;/i&gt;
    &lt;i class="iconfont icon-bianji icon_2"&gt;&lt;/i&gt;
    &lt;i class="iconfont icon-bianji icon_3"&gt;&lt;/i&gt;
    &lt;i class="iconfont icon-bianji icon_4"&gt;&lt;/i&gt;
    &lt;i class="iconfont icon-bianji icon_5"&gt;&lt;/i&gt;
        </code></pre></figure>
    </section>
</template>

<script>
    export default {
        name: "global-icon",
        data() {
            return {
                iconStyle:[
                    {style: 'icon_1',example: '图标大小'},
                    {style: 'icon_2',example: '图标大小'},
                    {style: 'icon_3',example: '图标大小'},
                    {style: 'icon_4',example: '图标大小'},
                    {style: 'icon_5',example: '图标大小'}
                ]
            }
        }
    }
</script>

<style scoped>

</style>



