<template>
    <section>
        <h2 id="form-upload-file"><a class="anchorjs-link font_2" href="#form-upload-file" aria-label="Anchor link for: form-upload-file"></a>上传文件</h2>
        <p class="text_des font_4">显示按钮名称和控件标签</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <button type="button" class="layui-btn" id="testUploadFile01">
                <i class="layui-icon">&#xe67c;</i>上传文件
            </button>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="UploadFile"&gt;
    &lt;label class="layui-form-label label" handler="label"&gt;上传控件&lt;/label&gt;
    &lt;button class="layui-btn" ds-event="upLoad" id="uploadFile"&gt;
        &lt;span class="layui-icon iconfont icon-yunduanshangchuan" handler="iconStyle" ds-event="upLoad" id="icon"&gt;&lt;/span&gt;
        &lt;span handler="btnName" ds-event="upLoad" class="btnName"&gt;文件上传&lt;/span&gt;
    &lt;/button&gt;
&lt;/div&gt;
        </code></pre></figure>

        <p class="text_des font_4">隐藏按钮名称和控件标签</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <button type="button" class="layui-btn" id="testUploadFile02">
                <i class="layui-icon">&#xe67c;</i>
            </button>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="UploadFile hideName hidelabel"&gt;
    &lt;label class="layui-form-label label" handler="label"&gt;上传控件&lt;/label&gt;
    &lt;button class="layui-btn" ds-event="upLoad" id="uploadFile"&gt;
        &lt;span class="layui-icon iconfont icon-yunduanshangchuan" handler="iconStyle" ds-event="upLoad" id="icon"&gt;&lt;/span&gt;
        &lt;span handler="btnName" ds-event="upLoad" class="btnName"&gt;文件上传&lt;/span&gt;
    &lt;/button&gt;
&lt;/div&gt;
        </code></pre></figure>

        <h4 class="font_3">上传文件列表</h4>
        <p class="text_des font_4">为了将上传的文件置于上传按钮下方的合适位置，需要将所有上传文件项包裹进.fileContainer 内;同时，为了使 单个上传文件能够呈现效果图的样式，需要将包含文件详情的DOM放在.fileContent中，其中.icon 类规定了上传 文件类型图标的基础样式。其他类名如下表:</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <table>
                <thead>
                <tr>
                    <th>类名</th>
                    <th>应用场景</th>
                </tr>
                </thead>
                <tbody>
                <tr v-for="item in uploadFileList">
                    <td>{{ item.className }}</td>
                    <td>{{ item.useful }}</td>
                </tr>
                </tbody>
            </table>
        </div>
        <pre v-highlightA><code>
//上传成功
&lt;div class="fileContainer"&gt;
    &lt;div class="fileContent"&gt;
        &lt;b class="icon"&gt;&lt;/b&gt;
        &lt;div class="fileName"&gt;上传文件1&lt;/div&gt;
        &lt;div class="deleteBtn"&gt;&lt;a class="deleteLink"&gt;删除&lt;/a&gt;&lt;/div&gt;
        &lt;div class="uploadState"&gt;
            &lt;span class="uploadeTxt">上传完成&lt;/span&gt;
        &lt;/div&gt;
    &lt;/div&gt;
&lt;/div&gt;
  //上传失败
&lt;div class="fileContainer"&gt;
    &lt;div class="fileContent"&gt;
        &lt;b class="icon"&gt;&lt;/b&gt;
        &lt;div class="fileName">上传文件1&lt;/div&gt;
        &lt;div class="deleteBtn"&gt;&lt;a class="deleteLink"&gt;删除&lt;/a&gt;&lt;/div&gt;
        &lt;div class="uploadState"&gt;
            &lt;span style="color:red">上传失败&lt;/span&gt;
        &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;
        </code></pre>
    </section>
</template>

<script>
    layui.use('upload', function(){
        var upload = layui.upload;
        //执行实例
        var uploadInst = upload.render({
            elem: '#testUploadFile01' //绑定元素
            ,url: '/upload/' //上传接口
            ,done: function(res){
                //上传完毕回调
            }
            ,error: function(){
                //请求异常回调
            }
        });

        var uploadInst = upload.render({
            elem: '#testUploadFile02' //绑定元素
            ,url: '/upload/' //上传接口
            ,done: function(res){
                //上传完毕回调
            }
            ,error: function(){
                //请求异常回调
            }
        });
    });
    export default {
        name: "form-upload-file",
        data () {
            return {
                uploadFileList:[
                    {className: 'fileName ',useful: '文件名称'},
                    {className: 'deleteBtn ',useful: '删除按钮'},
                    {className: 'deleteLink ',useful: '删除a标签'},
                    {className: 'uploadState ',useful: '上传状态基础样式'},
                    {className: 'uploadeTxt ',useful: '上传成功字体颜色'},
                ]
            }
        }
    }
</script>

<style scoped>
.ds_example tbody td {
    font-size: 16px;
    line-height: 40px;
}
</style>



