<template>
    <section>
        <h2 id="form-upload-pic"><a class="anchorjs-link font_2" href="#form-upload-pic" aria-label="Anchor link for: form-upload-pic"></a>上传图片</h2>
        <p class="text_des font_4">显示按钮名称和控件标签</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <button type="button" class="layui-btn" id="testUploadPic01">
                <i class="layui-icon">&#xe67c;</i>上传图片
            </button>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="UploadFile"&gt;
    &lt;label class="layui-form-label label" handler="label"&gt;上传控件&lt;/label&gt;
    &lt;button class="layui-btn" ds-event="upLoad" id="uploadFile"&gt;
        &lt;span class="layui-icon iconfont icon-yunduanshangchuan" handler="iconStyle" ds-event="upLoad" id="icon"&gt;&lt;/span&gt;
        &lt;span handler="btnName" ds-event="upLoad" class="btnName"&gt;上传图片&lt;/span&gt;
    &lt;/button&gt;
&lt;/div&gt;
        </code></pre></figure>

        <p class="text_des font_4">隐藏按钮名称和控件标签</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <button type="button" class="layui-btn" id="testUploadPic02">
                <i class="layui-icon">&#xe67c;</i>
            </button>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="UploadFile hideName hidelabel"&gt;
    &lt;label class="layui-form-label label" handler="label"&gt;上传控件&lt;/label&gt;
    &lt;button class="layui-btn" ds-event="upLoad" id="uploadFile"&gt;
        &lt;span class="layui-icon iconfont icon-yunduanshangchuan" handler="iconStyle" ds-event="upLoad" id="icon"&gt;&lt;/span&gt;
        &lt;span handler="btnName" ds-event="upLoad" class="btnName"&gt;文件上传&lt;/span&gt;
    &lt;/button&gt;
&lt;/div&gt;
        </code></pre></figure>

        <h5 class="text_des font_3">上传图片列表</h5>
        <p class="text_des font_4">列表容器类.imgContainer ,需要将上传的所有文件包裹在此类中，统一管理;单个上传的文件Dom 需要包裹 在.item中</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <table>
            <thead>
            <tr>
                <th>类名</th>
                <th>应用类型</th>
            </tr>
            </thead>
            <tbody>
            <tr v-for="item in uploadPicList">
                <td>{{ item.className }}</td>
                <td>{{ item.useful }}</td>
            </tr>
            </tbody>
        </table>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="imgContainer"&gt;
    &lt;div class="layui-row item"&gt;
        &lt;div class="layui-col-md1"&gt;
            &lt;div class="order"&gt;1.&lt;/div&gt;&lt;/div&gt;
        &lt;div class="layui-col-md2"&gt;
            &lt;div class="pic operate sizeUp"&gt;
                &lt;img src="....." alt=""&gt;&lt;/div&gt;
        &lt;/div&gt;
        &lt;div class="layui-col-md8"&gt;
            &lt;div class="layui-col-md5"&gt;
                &lt;div class="picName"&gt;图片名称&lt;/div&gt;&lt;/div&gt;
            &lt;div class="layui-col-md3"&gt;
                &lt;div&gt;0.25M&lt;/div&gt;&lt;/div&gt;
        &lt;/div&gt;
        &lt;div class="layui-col-md1 operate"&gt;
            &lt;div class="layui-col-md6"&gt;
                &lt;a class="downLoad iconfont" href="...." download="图片名称"&gt;&#xec22;&lt;/a&gt;&lt;/div&gt;
            &lt;div class="layui-col-md6"&gt;
                &lt;div class="delete iconfont"&gt;&#xe61b;&lt;/div&gt;&lt;/div&gt;
        &lt;/div&gt;
    &lt;/div&gt;
&lt;/div&gt;
        </code></pre></figure>
    </section>
</template>

<script>
    layui.use('upload', function(){
        var upload = layui.upload;
        //执行实例
        var uploadInst = upload.render({
            elem: '#testUploadPic01' //绑定元素
            ,url: '/upload/' //上传接口
            ,done: function(res){
                //上传完毕回调
            }
            ,error: function(){
                //请求异常回调
            }
        });

        var uploadInst = upload.render({
            elem: '#testUploadPic02' //绑定元素
            ,url: '/upload/' //上传接口
            ,done: function(res){
                //上传完毕回调
            }
            ,error: function(){
                //请求异常回调
            }
        });
    });
    export default {
        name: "form-upload-pic",
        data () {
            return {
                uploadPicList:[
                    {className: 'pic ',useful: '图片大小'},
                    {className: 'picName ',useful: '图片名称'},
                    {className: 'operate ',useful: '操作栏样式'}
                ]
            }
        }
    }
</script>

<style scoped>
.ds_example tbody td {
    font-size: 16px;
    line-height: 40px;
}
</style>



