<template>
    <section>
        <h2 id="global-color"><a class="anchorjs-link font_2" href="#global-color" aria-label="Anchor link for: global-color"></a>颜色</h2>

        <div class="ds_example">
            <h5 class="font_4">实例：</h5>
            <table class="color-table">
                <thead>
                <tr>
                    <th width="100">样式命名</th>
                    <th width="120">界面主题颜色</th>
                    <th width="80">色值</th>
                    <th width="200">使用场景</th>
                </tr>
                </thead>
                <tbody>
                <tr v-for="item in colorStyle">
                    <td>{{ item.style }}</td>
                    <td class="color_area">
                        <p :class="item.color">{{ item.example }}</p>
                    </td>
                    <td>{{ item.color_value }}</td>
                    <td> {{ item.useful }} </td>
                </tr>
                </tbody>
            </table>
        </div>

    </section>
</template>

<script>
    export default {
        name: "global-color",
        data() {
            return {
                colorStyle: [
                    {style: '主色',color:'main_color',color_value:'#c62f26',useful:'页面的主题色，小面积使用，用于侧边导航及菜单'},
                    {style: '辅色',color:'auxiliary_color',color_value:'#ff7200',useful:'小面积使用，用于部分提示文字及按钮'},
                    {style: '文字一',color:'text_01',color_value:'#333333',useful:'主要文字信息用色'},
                    {style: '文字二',color:'text_02',color_value:'#999999',useful:'次要文字信息用色'},
                    {style: '分割',color:'segment',color_value:'#d0d0d0',useful:'用于分割线'},
                    {style: '底色',color:'bg_color',color_value:'#f6f6f6',useful:'用于分割模块的底色及背景色'},
                    {style: '模块色',color:'module_color',color_value:'#ffffff',useful:'用于所用模块用色，白色'},
                ]
            }
        }
    }
</script>

<style scoped>
.main_color {
    background-color: #c62f26;
}
.auxiliary_color {
    background-color: #ff7200;
}
.text_01 {
    background-color: #333;
}
.text_02 {
    background-color: #999;
}
.segment {
    background-color: #d0d0d0;
}
.bg_color {
    background-color: #f6f6f6;
}
.module_color {
    background-color: #ffffff;
}
.color-table tbody td {
    line-height: 40px;
}
.color_area {
    position: relative;
}
.color_area>p {
    position: absolute;
    top: 10px;
    width: 100px;
    height: 20px;
}
.color-table tbody tr:nth-of-type(7) .color_area p {
    border: 1px solid #eee;
    margin: -1px;
}
</style>



