<template>
    <section>
        <h2 id="form-date"><a class="anchorjs-link font_2" href="#form-date" aria-label="Anchor link for: form-date"></a>日期</h2>
        <p class="text_des font_4">显示 label 标签</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <div class="layui-inline">
                <label class="layui-form-label" style="width: 100px;">请选择日期</label>
                <div class="layui-input-inline">
                    <input type="text" class="layui-input" id="testDate01" placeholder="yyyy-MM-dd">
                </div>
            </div>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="ds_datepicker"&gt;
    &lt;label class="layui-form-label" for="datepicker" handler="label"&gt; 请选择日期&lt;/label&gt;
    &lt;div class="layui-input-block"&gt;
        &lt;input type="text" class="layui-input" id="datepicker" handler="picker"&gt;
    &lt;/div&gt;
&lt;/div&gt;
        </code></pre></figure>

        <p class="text_des font_4">给父元素添加 ***.hideLabel*** 类 ，隐藏label 标签</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <div class="layui-inline">
                <div class="layui-input-inline">
                    <input type="text" class="layui-input" id="testDate02" placeholder="yyyy-MM-dd">
                </div>
            </div>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="ds_datepicker hideLabel"&gt;
    &lt;label class="layui-form-label" for="datepicker" handler="label"&gt; 请选择日期&lt;/label&gt;
    &lt;div class="layui-input-block"&gt;
        &lt;input type="text" class="layui-input" id="datepicker" handler="picker"&gt;
    &lt;/div&gt;
&lt;/div&gt;
        </code></pre></figure>
    </section>
</template>

<script>
    layui.use('laydate', function() {
        var laydate = layui.laydate;

        //常规用法
        laydate.render({
            elem: '#testDate01'
        });
        laydate.render({
            elem: '#testDate02'
        });
    });
    export default {
        name: "form-date"
    }
</script>

<style scoped>

</style>



