<template>
    <section>
        <h2 id="pageNav-tree"><a class="anchorjs-link font_2" href="#pageNav-tree" aria-label="Anchor link for: pageNav tree"></a>导航树</h2>
        <ol class="dataList font_4" style="margin-left: 36px">
            <li style="padding-left: 10px;list-style: decimal;" v-for="item in navTreeList">{{ item.text }}</li>
        </ol>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <div class="ds_NavTree ds_panel">
                <div class="head">
                    <div class="title ">
                        <label class="font_2">标题</label>
                    </div>
                </div>
                <div class="body">
                    <div class="ds_tree">
                        <div class="ztree arrowsTree" handler="tree" id="doctree"></div>
                    </div>
                </div>
            </div>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="ds_NavTree ds_panel"&gt;
    &lt;div class="head"&gt;
        &lt;div class="title "&gt;
            &lt;label class="font_2">标题&lt;/label&gt;
        &lt;/div&gt;
    &lt;/div&gt;
    &lt;div class="body"&gt;
        &lt;div class="ds_tree"&gt;
            &lt;div class="ztree">&lt;/div&gt;
        &lt;/div&gt;
    &lt;/div&gt;
&lt;/div&gt;
        </code></pre></figure>
    </section>
</template>

<script>

    import "./../../../../static/zTree_v3/js/jquery.ztree.core.min.js"
    import "./../../../../static/zTree_v3/js/jquery.ztree.excheck.min.js"

    export default {
        name: "nav-tree",
        data() {
            return {
                navTreeList: [
                    {text: '导航树面板依赖 .ds_NavTree 和 .ds_panel'},
                    {text: '.head 下的 .title 是指明导航树的标题内容，标题一般使用 .font_2 文字大小'},
                    {text: '.body 内部的代码则是存放树的内容，树依赖 .ztree 给 .ztree 追加 .arrowsTree 会使树变成箭头风格，那么不使用 .arrowsTree 箭头模式 则会变成原始树风格，'}
                ],
                setting: {
                    view: {showLine: true, showIcon: true}
                },
                zNodes: [
                    {
                        id: 1,
                        pId: 0,
                        name: "公文",
                        open: "true",
                        children: [
                            {id: 11, pId: 1, name: "发文"},
                            {id: 12, pId: 1, name: "收文"},
                            {id: 110100000000, pId: 1, name: "签报"},
                        ]
                    },
                    {
                        id: 2,
                        pId: 0,
                        name: "报销",
                        open: "true",
                        children: [
                            {id: 21, pId: 2, name: "日常报销"},
                            {
                                id: 22,
                                pId: 2,
                                name: "项目报销",
                                open: "true",
                                children: [
                                    {id: 221, pId: 22, name: "内部项目"},
                                    {id: 222, pId: 22, name: "外部项目"}
                                ]
                            }
                        ]
                    }
                ]
            }
        },
        mounted() {
            $.fn.zTree.init($("#doctree"), this.setting, this.zNodes);
        }
    }
</script>

<style scoped>
    .ds_panel > .head {
        position: static;
    }
    .ds_panel > .body {
        margin: 0;
        position: static;
    }
</style>



