<template>
    <section>
        <h2 id="pageNav-tabs"><a class="anchorjs-link font_2" href="#pageNav-tabs" aria-label="Anchor link for: pageNav tabs"></a>选项卡</h2>
        <ol class="dataList font_4" style="margin-left: 36px">
            <li style="padding-left: 10px;list-style: decimal;" v-for="item in navTabsList">{{ item.text }}</li>
        </ol>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <div class="layui-tab layui-tab-brief">
                <ul class="layui-tab-title">
                    <li class="layui-this">Tab1</li>
                    <li>Tab2</li>
                    <li>Tab3</li>
                </ul>
                <div class="layui-tab-content" style="height: 100px;">
                    <div class="layui-tab-item layui-show">Tab1</div>
                    <div class="layui-tab-item">Tab2</div>
                    <div class="layui-tab-item">Tab3</div>
                </div>
            </div>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="ds_tab layui-tab layui-tab-brief"&gt;
    &lt;ul class="layui-tab-title"&gt;
        &lt;li class="layui-this"&gt;Tab1&lt;/li&gt;
        &lt;li&gt;Tab2&lt;/li&gt;
        &lt;li&gt;Tab3&lt;/li&gt;
    &lt;/ul&gt;
    &lt;div class="layui-tab-content"&gt;
        &lt;div class="layui-tab-item layui-show"&gt;Tab1&lt;/div&gt;
        &lt;div class="layui-tab-item"&gt;Tab2&lt;/div&gt;
        &lt;div class="layui-tab-item"&gt;Tab3&lt;/div&gt;
    &lt;/div&gt;
&lt;/div&gt;
        </code></pre></figure>

        <p class="text_des font_4">支持删除选项卡，可以对 .layui-tab 容器设置属性 lay-allowClose="true" 来允许Tab选项卡被删除</p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <div class="layui-tab layui-tab-card" lay-allowclose="true">
                <ul class="layui-tab-title">
                    <li class="layui-this">Tab1</li>
                    <li>Tab2</li>
                    <li>Tab3</li>
                    <li>Tab4</li>
                </ul>
                <div class="layui-tab-content" style="height: 100px;">
                    <div class="layui-tab-item layui-show">Tab1</div>
                    <div class="layui-tab-item">Tab2</div>
                    <div class="layui-tab-item">Tab3</div>
                    <div class="layui-tab-item">Tab4</div>
                </div>
            </div>
        </div>
        <figure class="highlight"><pre v-highlightA><code>
&lt;div class="ds_tab layui-tab layui-tab-card" lay-allowclose="true"&gt;
    &lt;ul class="layui-tab-title"&gt;
        &lt;li class="layui-this"&gt;Tab1&lt;/li&gt;
        &lt;li&gt;Tab2&lt;/li&gt;
        &lt;li&gt;Tab3&lt;/li&gt;
        &lt;li&gt;Tab4&lt;/li&gt;
    &lt;/ul&gt;
    &lt;div class="layui-tab-content"&gt;
        &lt;div class="layui-tab-item layui-show"&gt;Tab1&lt;/div&gt;
        &lt;div class="layui-tab-item"&gt;Tab2&lt;/div&gt;
        &lt;div class="layui-tab-item"&gt;Tab3&lt;/div&gt;
        &lt;div class="layui-tab-item"&gt;Tab4&lt;/div&gt;
    &lt;/div&gt;
&lt;/div&gt;
        </code></pre></figure>

    </section>
</template>

<script>
    layui.use('element', function(){
        var $ = layui.jquery
            ,element = layui.element; //Tab的切换功能，切换事件监听等，需要依赖element模块

    });
    export default {
        name: "nav-tabs",
        data() {
            return {
                navTabsList:[
                    {text:'选项卡依赖 .ds_tab 和 .layui_tab'},
                    {text:'选中高亮样式继承主题色'},
                    {text:'内置多种风格，删除.layui-tab-brief可切换为原始模式。可通过给.layui-tab 追加 .layui-tab-card可切换为卡片模式'}
                ]
            }
        }
    }
</script>

<style scoped>

</style>



