<template>
    <div class="container">
        <div class="row">
            <div class="col-md-3">
                <nav-menu></nav-menu>
            </div>
            <div class="col-md-9">
                <!--  全局样式  -->
                <global-control></global-control>
                <!--  表单  -->
                <form-control></form-control>
                <!--  导航  -->
                <nav-control></nav-control>
            </div>
        </div>
    </div>
</template>
<script>
    import globalControl from './page-global/pageGlobal'
    import navMenu from './../styleDocs/navMenu/navMenu'
    import formControl from './page-form/pageForm'
    import navControl from './page-nav/nav'

    export default {
        name: "styleIndex",
        components: {
            globalControl,navMenu,navControl,formControl
        },
        data() {
            return {}
        },
        mounted: function () {
            $(function () {
                $('.nav').find('a').click(function () {
                    $('.nav').find('a').removeClass('active')
                    $(this).addClass('active')
                })
            });
        },
    }
</script>

<style scoped>

</style>



