<template>
    <section>
        <h2 id="global-font"><a class="anchorjs-link font_2" href="#global-font" aria-label="Anchor link for: global-font"></a>文字</h2>
        <h4 class="font_3">文字大小（6种）</h4>
        <p class="text_des font_4">提供  .font_1 到 .font_6  6个类  赋予相应的文字不同大小样式 </p>
        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <table class="font-table">
                <thead>
                <tr>
                    <th width="100">样式</th>
                    <th width="150">举例</th>
                    <th width="80">字号</th>
                    <th width="200">使用场景</th>
                </tr>
                </thead>
                <tbody>
                <tr v-for="item in fontStyle">
                    <td>{{ item.style }}</td>
                    <td>
                        <h3 :class="item.style">{{ item.example }}</h3>
                    </td>
                    <td>{{ item.font_size }}</td>
                    <td> {{ item.useful }} </td>
                </tr>
                </tbody>
            </table>
        </div>

        <figure class="highlight"><pre v-highlightA><code>
    &lt;h1 class="font_1"&gt;文字大小&lt;/h1&gt;
    &lt;h2 class="font_2"&gt;文字大小&lt;/h2&gt;
    &lt;h3 class="font_3"&gt;文字大小&lt;/h3&gt;
    &lt;h4 class="font_4"&gt;文字大小&lt;/h4&gt;
    &lt;h5 class="font_5"&gt;文字大小&lt;/h5&gt;
    &lt;h6 class="font_6"&gt;文字大小&lt;/h6&gt;
        </code></pre></figure>

    </section>
</template>

<script>
    export default {
        name: "global-font",
        data() {
            return {
                fontStyleList: [
                    {text: '单行显示：.nowrap',img:require('../../../assets/img/global/text-nowrap.png')},
                    {text: '单行显示省略：.ellipsis',img:require('../../../assets/img/global/text-ellipsis.png')},
                    {text: '主题文字样式：.font-color,  文本Tab1使用了.font-color',img:require('../../../assets/img/global/text-font-color.png')},
                    {text: '标题：.title,  文本Tab2使用了.title',img:require('../../../assets/img/global/text-title.png')},
                ],
                fontStyle:[
                    {style: 'font_1',example: '文字大小',font_size: '34px',useful: '用在少数量重要标题'},
                    {style: 'font_2',example: '文字大小',font_size: '24px',useful: '用在较为重要的文字'},
                    {style: 'font_3',example: '文字大小',font_size: '18px',useful: '用于重要标题'},
                    {style: 'font_4',example: '文字大小',font_size: '16px',useful: '部件页签/部件内部分组/表单内部分组'},
                    {style: 'font_5',example: '文字大小',font_size: '14px',useful: '用于大多数文字'},
                    {style: 'font_6',example: '文字大小',font_size: '12px',useful: '用于引用文字/部件内容副标题/角标'}
                ]
            }
        }
    }
</script>

<style scoped>
.font-table tbody{
    color: #666;
}
</style>



