<template>
    <section>
        <h2 id="global-btn"><a class="anchorjs-link font_2" href="#global-btn" aria-label="Anchor link for: global-btn"></a>按钮</h2>

        <div class="ds_example">
            <h5 class="font_5">实例：</h5>
            <table class="btn-table">
                <thead>
                <tr>
                    <th width="100"></th>
                    <th width="60"></th>
                    <th width="100"></th>
                    <th width="60"></th>
                </tr>
                </thead>
                <tbody>
                <tr>
                    <td>
                        <a class="ds_button"><i class="iconfont icon-hao"></i>主要按钮</a>
                    </td>
                    <td>主要按钮</td>
                    <td>
                        <a class="ds_button ds_button_sm"><i class="iconfont icon-hao"></i>主要按钮</a>
                    </td>
                    <td>主要按钮 小</td>
                </tr>
                <tr>
                    <td>
                        <a class="ds_button ds_button_primary"><i class="iconfont icon-shanchu"></i>次要按钮</a>
                    </td>
                    <td>次要按钮</td>
                    <td>
                        <a class="ds_button ds_button_primary ds_button_sm"><i class="iconfont icon-shanchu"></i>次要按钮</a>
                    </td>
                    <td>次要按钮 小</td>
                </tr>
                <tr>
                    <td>
                        <a class="ds_button ds_icon_button "><i class="iconfont icon-shanchu" ></i></a>
                    </td>
                    <td>图标按钮</td>
                    <td>
                        <a class="ds_button ds_icon_button ds_icon_button_sm"><i class="iconfont icon-shanchu" ></i></a>
                    </td>
                    <td>图标按钮 小</td>
                </tr>
                <tr>
                    <td>
                        <a class="ds_button ds_icon_button_text ">
                            <i class="iconfont icon-bianji"></i>
                            <div>编辑</div>
                        </a>
                    </td>
                    <td>图标文字按钮</td>
                    <td>
                        <a class="ds_button ds_icon_button_text  ds_icon_button_text_sm">
                            <i class="iconfont icon-bianji"></i>
                            <div>编辑</div>
                        </a>
                    </td>
                    <td>图标文字按钮 小</td>
                </tr>
                </tbody>
            </table>
        </div>

        <figure class="highlight"><pre v-highlightA><code>
// 主要按钮
    &lt;a class="ds_button"&gt;&lt;i class="iconfont icon-hao">&lt;/i>主要按钮&lt;/a&gt;
// 主要按钮 小
     &lt;a class="ds_button ds_button_sm"&gt;&lt;i class="iconfont icon-hao"&gt;&lt;/i&gt;主要按钮&lt;/a&gt;

// 次要按钮
    &lt;a class="ds_button ds_button_primary"&gt;&lt;i class="iconfont icon-shanchu"&gt;&lt;/i&gt;次要按钮&lt;/a&gt;
// 次要按钮 小
     &lt;a class="ds_button ds_button_primary ds_button_sm">&lt;i class="iconfont icon-shanchu"&gt;&lt;/i&gt;次要按钮&lt;/a&gt;

// 图标按钮
    &lt;a class="ds_button ds_icon_button "&gt;&lt;i class="iconfont icon-shanchu" &gt;&lt;/i&gt;&lt;/a&gt;
// 图标按钮 小
    &lt;a class="ds_button ds_icon_button ds_icon_button_sm"&gt;&lt;i class="iconfont icon-shanchu" &gt;&lt;/i&gt;&lt;/a&gt;

// 图标带文字
    &lt;a class="ds_button ds_icon_button_text "&gt;
        &lt;i class="iconfont icon-bianji"&gt;&lt;/i&gt;
        &lt;div>编辑&lt;/div&gt;
    &lt;/a&gt;
// 图标带文字 小
     &lt;a class="ds_button ds_icon_button_text  ds_icon_button_text_sm"&gt;
         &lt;i class="iconfont icon-bianji"&gt;&lt;/i&gt;
         &lt;div>编辑&lt;/div&gt;
     &lt;/a&gt;
        </code></pre></figure>

    </section>
</template>

<script>
    export default {
        name: "global-btn",
        data() {
            return {
                btnStyleList:[
                    {className: '.layui-btn',useful:'layui按钮'},
                    {className: '.ds-button',useful:'无边框无背景按钮基类class'},
                    {className: '.ds-icon-button',useful:'带图标的按钮'},
                    {className: '.ds-icon-button-sm',useful:'带图标的小按钮'},
                    {className: '.ds-icon-button-text',useful:'图文按钮'},
                    {className: '.ds-icon-button-text-sm',useful:'图文小按钮'},
                ]
            }
        }
    }
</script>

<style scoped>
.btn-table tbody td {
    padding: 10px 0;
}
</style>



