import Vue from 'vue'
import Router from 'vue-router'
import styleIndex from '@/components/styleDocs/styleIndex'

Vue.use(Router)

export default new Router({
    routes: [
        {
            path: '/',
            name: 'styleIndex',
            component: styleIndex
        }
    ]
})



